import{_ as a,c as l,o as e,ag as n}from"./chunks/framework.B-XtCDNB.js";const D=JSON.parse('{"title":"Getting Started with LinkedQL","description":"","frontmatter":{},"headers":[],"relativePath":"docs.md","filePath":"docs.md"}'),t={name:"docs.md"};function o(p,s,i,r,c,d){return e(),l("div",null,[...s[0]||(s[0]=[n(`<h1 id="getting-started-with-linkedql" tabindex="-1">Getting Started with LinkedQL <a class="header-anchor" href="#getting-started-with-linkedql" aria-label="Permalink to &quot;Getting Started with LinkedQL&quot;">​</a></h1><p>This guide takes you from installation to your first query with LinkedQL.</p><p>If you are totally new here, you may want to begin with <a href="/overview">What is LinkedQL</a>. If you already know you want the embeddable local runtime, jump to <a href="/flashql">FlashQL</a>.</p><h2 id="the-idea-in-one-minute" tabindex="-1">The idea in one minute <a class="header-anchor" href="#the-idea-in-one-minute" aria-label="Permalink to &quot;The idea in one minute&quot;">​</a></h2><p>LinkedQL keeps one application-facing shape across very different runtimes:</p><ul><li><code>db.query()</code> for regular SQL execution and live queries</li><li><code>db.stream()</code> for lazy row-by-row reads</li><li><code>db.transaction()</code> for explicit transactions</li><li><code>db.wal.subscribe()</code> for table-level changefeeds</li></ul><p>one consistent API surface, whether <code>db</code> is:</p><ul><li>PostgreSQL</li><li>MySQL</li><li>MariaDB</li><li>an edge client</li><li>FlashQL, the local embeddable engine</li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Install the package from npm:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">npm</span><span style="color:#C3E88D;"> install</span><span style="color:#C3E88D;"> @linked-db/linked-ql</span></span></code></pre></div><p>The package exports client entry points such as:</p><ul><li><code>@linked-db/linked-ql/postgres</code></li><li><code>@linked-db/linked-ql/mysql</code></li><li><code>@linked-db/linked-ql/mariadb</code></li><li><code>@linked-db/linked-ql/edge</code></li><li><code>@linked-db/linked-ql/edge-worker</code></li><li><code>@linked-db/linked-ql/flashql</code></li></ul><h2 id="your-first-query-direct-database-client" tabindex="-1">Your first query: direct database client <a class="header-anchor" href="#your-first-query-direct-database-client" aria-label="Permalink to &quot;Your first query: direct database client&quot;">​</a></h2><p>A good first look is with a regular database client.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> PGClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  host</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">localhost</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  port</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 5432</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  user</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  password</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">password</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  database</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">myapp</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT 10 AS value</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ value: 10 }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h2 id="your-first-query-local-runtime-with-flashql" tabindex="-1">Your first query: local runtime with FlashQL <a class="header-anchor" href="#your-first-query-local-runtime-with-flashql" aria-label="Permalink to &quot;Your first query: local runtime with FlashQL&quot;">​</a></h2><p>LinkedQL ships with FlashQL, an embeddable SQL runtime that runs in-process.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  CREATE TABLE public.users (</span></span>
<span class="line"><span style="color:#C3E88D;">    id INT PRIMARY KEY,</span></span>
<span class="line"><span style="color:#C3E88D;">    name TEXT</span></span>
<span class="line"><span style="color:#C3E88D;">  )</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  INSERT INTO public.users (id, name)</span></span>
<span class="line"><span style="color:#C3E88D;">  VALUES (1, &#39;Ada&#39;), (2, &#39;Linus&#39;)</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, name</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ id: 1, name: &#39;Ada&#39; }, { id: 2, name: &#39;Linus&#39; }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>FlashQL is a real local runtime with the same top-level query surface as the mainstream clients.</p><h2 id="which-client-should-you-start-with" tabindex="-1">Which client should you start with? <a class="header-anchor" href="#which-client-should-you-start-with" aria-label="Permalink to &quot;Which client should you start with?&quot;">​</a></h2><p>Use the client that matches where the query should run:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Client</th><th style="text-align:left;">Use it when</th><th style="text-align:left;">Guide</th></tr></thead><tbody><tr><td style="text-align:left;"><code>PGClient</code></td><td style="text-align:left;">your app talks directly to PostgreSQL</td><td style="text-align:left;"><a href="/docs/setup#postgresql">Dialects &amp; Clients</a></td></tr><tr><td style="text-align:left;"><code>MySQLClient</code></td><td style="text-align:left;">your app talks directly to MySQL</td><td style="text-align:left;"><a href="/docs/setup#mysql">Dialects &amp; Clients</a></td></tr><tr><td style="text-align:left;"><code>MariaDBClient</code></td><td style="text-align:left;">your app talks directly to MariaDB</td><td style="text-align:left;"><a href="/docs/setup#mariadb">Dialects &amp; Clients</a></td></tr><tr><td style="text-align:left;"><code>EdgeClient</code></td><td style="text-align:left;">your app lives in the browser or on the edge and needs to talk to the database in a remote worker or server</td><td style="text-align:left;"><a href="/docs/setup#edgeclient">Dialects &amp; Clients</a></td></tr><tr><td style="text-align:left;"><code>FlashQL</code></td><td style="text-align:left;">you want an embeddable local SQL runtime</td><td style="text-align:left;"><a href="/docs/setup#flashql">Dialects &amp; Clients</a></td></tr></tbody></table><p>LinkedQL is designed for these architectural options.</p><h2 id="what-comes-next" tabindex="-1">What comes next <a class="header-anchor" href="#what-comes-next" aria-label="Permalink to &quot;What comes next&quot;">​</a></h2><p>While deliberately simple, the same interface above quickly opens into deeper grounds:</p><ul><li>live queries with <code>{ live: true }</code></li><li>lazy result streaming with <code>db.stream()</code></li><li>table-level changefeeds with <code>db.wal.subscribe()</code></li><li>language extensions such as DeepRefs and JSON literals</li><li>FlashQL orchestration with foreign namespaces, <code>origin</code> views, <code>materialized</code> views, <code>realtime</code> views, and <code>db.sync.sync()</code></li></ul><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="/docs/setup">Dialects &amp; Clients</a> for setup by runtime</li><li><a href="/docs/query-api">Query Interface</a> for the common method contract</li><li><a href="/capabilities">Capabilities Overview</a> for language and runtime extensions</li><li><a href="/flashql">FlashQL</a> for the local runtime and sync model</li></ul>`,29)])])}const F=a(t,[["render",o]]);export{D as __pageData,F as default};
